#include "stepper_28byj.h"
#include <Stepper.h>
#define STEPS_PER_REV 2048
static Stepper motor(STEPS_PER_REV,25,27,26,14);
void stepper_28byj_setup(){motor.setSpeed(15);Serial.println("[28byj] OK");}
void stepper_28byj_step(int s){motor.step(s);}
void stepper_28byj_set_speed(int rpm){motor.setSpeed(rpm);}
